var e=JSON.parse(`[{"id":"L1_1","type":"subtitle","speaker":null,"text":{"KOREA":"10년 후, 겨울","JPN":"10年後、冬","ENG":"Ten years later, winter.","TWN":"10年後的冬天","SCN":"10年后，冬天","DEU":"Ten years later, winter.","FRA":"Ten years later, winter."},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"후우…","JPN":"ふう……","ENG":"Whew…","TWN":"呼…"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"보고 드립니다.","JPN":"報告します。","ENG":"Reporting in.","TWN":"報告。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"작전 중 악화된 용혈이 결국 폭주했고… 주시 대상은 사망했어요.","JPN":"作戦中悪化した龍血が暴走し……監視対象は死亡しました。","ENG":"During the operation, the Dragon Blood condition worsened and eventually went out of control… The subject is dead.","TWN":"作戰中惡化的龍血最終暴走了…監視對象死亡了。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"많이 힘들어 보이는군요.","JPN":"疲れているようですね。","ENG":"You look like you've been through a lot.","TWN":"你看起來很辛苦。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"전 감시만 하라고 했을 텐데, 그 사람의 폭주를 직접 막으려 했던 건가요?","JPN":"僕が指示したのは監視だけのはずですが、彼女の暴走を止めようとしたのですか？","ENG":"I told you to observe. Did you try to stop her rampage yourself?","TWN":"我只讓你監視，但你是不是親自去阻止她的暴走了？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…면목 없습니다, 대장.","JPN":"……申し訳ありません、隊長。","ENG":"…I accept full responsibility, Commander.","TWN":"…很抱歉，隊長。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"생애 가장 행복해야 할 순간에 죽는다… 정말 안타까운 비극이지만, 운명에 우리가 관여할 수 있는 건 없어요.","JPN":"最も幸せであるべき瞬間に死ぬ……残念でならない悲劇ですが、僕たちが運命に干渉できる術はありません。","ENG":"To die in the happiest moment of one's life… A tragic end, no doubt. But fate isn't something we can change.","TWN":"在人生最幸福的時刻死去…雖然是個令人惋惜的悲劇，但我們無法干涉命運。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그래도 당신이 무사해서 다행이네요.","JPN":"ですが、あなたが無事でよかったです。","ENG":"Still, I'm relieved you made it back alive.","TWN":"不過，你平安無事真是太好了。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…마지막 순간, 예정대로 발키리가 개입해 폭주를 중재했습니다.","JPN":"……最後の瞬間、予定通りヴァルキリーが介入し、暴走を仲裁しました。","ENG":"…At the very end, Valkyrie intervened.","TWN":"…在最後一刻，女武神如預定地介入，阻止了暴走。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"제 정체를 들키진 않았습니다만… 그 여자도 전말을 모두 이해하고 있던 것처럼 태연하게 대응하더군요.","JPN":"正体はバレませんでしたが……前後の事情をすべて分かっていたかのように、冷静に対応していました。","ENG":"She didn't uncover my identity… but she acted like she already understood everything.","TWN":"我沒有暴露身分…但那個女人卻像是完全了解所有事情一樣，冷靜地應對。"},"stage":{"bg":"WINTER_STREET","slots":{"L":null,"C":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"발키리는 저희와 달리, 정보를 접해서 알고 있는 게 아닙니다.","JPN":"ヴァルキリーは僕たちと違って、事前に情報を入手したから知っていたわけではありません。","ENG":"Valkyrie isn't like us. She didn't learn that through intel.","TWN":"女武神和我們不同，她不是從情報中得知的。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L17_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"그렇다면…?","JPN":"ということは……？","ENG":"Then…?","TWN":"那麼…？"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"경험에서 우러나오는 반응이죠. 대격세혈맥의 보유자들을 수 없이 만나 왔을 테니까요.","JPN":"経験から出る反応です。対隔世血脈の保有者たちに幾度も会ってきたはずですから。","ENG":"It's from experience. She's crossed paths with Atavism hosts countless times.","TWN":"那是源於經驗的反應。她一定遇過無數大劫世血脈的擁有者。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고 그 최후 또한 수 없이 보아왔을 겁니다.","JPN":"そして彼らの最期もまた、幾度も見てきたはずです。","ENG":"And she's watched each of them meet their end.","TWN":"她也見證了無數次的最終結局。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_DESPAIR"}}}},{"id":"L21_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"여자의 아들은 그 아수라장에서도 결국 살아남았습니다.","JPN":"女の息子はあの修羅場でも生き残りました。","ENG":"Even in that chaos, the woman's son managed to survive.","TWN":"那名女子的兒子，即便身處那場混亂，最終仍然活了下來。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"생애 가장 행복한 순간이 아직 오지 않았다… 소년이 살아남은 이유는 그런 겁니다.","JPN":"まだ生涯で最も幸せな瞬間は訪れていない……少年が生き残った理由でしょう。","ENG":"Then maybe the happiest moment hadn't come yet… That could be why the boy lived.","TWN":"他人生最幸福的時刻還沒到來…這就是那個少年活下來的原因吧。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"이로서 용혈보유자는 한 사람 밖에 남지 않게 됐군요.","JPN":"これで龍血の保有者は1人になりましたね。","ENG":"And now, there's only one Dragon Blood host left.","TWN":"如此一來，龍血擁有者只剩下一個人了。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그리고… 끝내 용혈의 저주를 이겨내지 못하는 최후를 맞게 되겠죠.","JPN":"そして……龍血の呪いに打ち勝てず最期を迎えるでしょう。","ENG":"And… like all the others, will eventually lose to the curse.","TWN":"而…他最終也會迎來無法戰勝龍血詛咒的結局。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L25_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"지금껏 그랬던 것처럼.","JPN":"今までそうだったように。","ENG":"Just like always.","TWN":"就像過去一樣。"},"stage":{"bg":"WINTER_STREET","slots":{"L":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"JISOO_NPC_NULL_14","face":"UNIT_IDLE"}}}},{"id":"L28_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"명달은 살아 생전 그 굴레의 끝을 본 적이 없어요. 그럼에도 용의 혈맥이 계속 이어지길 바라는 사람이었습니다.","JPN":"アカタツは生前、その循環の最後を見たことがありませんでした。にもかかわらず、彼は龍の血脈が続いてほしいと願っていました。","ENG":"Myeongdal never lived to see the end of that cycle. Yet he still wished the Dragon's bloodline would go on.","TWN":"明達生前從未見過這個循環的盡頭。儘管如此，他還是希望龍的血脈能夠繼續延續。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"미래를 보는 사람이었음에도 자신이 보지 못하는 걸 믿었을 지도 모르죠.","JPN":"未来を見ることのできる人間でありながらも、自分が見ることのできない何かを信じていたのかもしれません。","ENG":"Maybe, despite being someone who saw the future, he chose to believe in what he couldn't see.","TWN":"他雖然是個能預知未來的人，但或許他相信自己看不到的東西。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"훗날 그 악순환을 끊어낼 누군가 나타날 거라고.","JPN":"後日、その悪循環を断ち切る誰かが現れてくれると。","ENG":"That someday, someone would break the vicious cycle.","TWN":"總有一天，會有人出現，切斷這個惡性循環。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"JISOO_NPC_NULL_14","text":{"KOREA":"…….","JPN":"……","ENG":"…","TWN":"……"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"그러니 가끔은 희망을 가져보자고요. 혹시 모르잖습니까.","JPN":"だからたまには希望を持ってみましょう。まだ分からないじゃないですか。","ENG":"So let's try having a little hope. You never know.","TWN":"所以，偶爾抱持希望吧。誰知道呢。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"NAYUBIN_SIX_NULL_NULL","text":{"KOREA":"연옥에 떨어진 번뇌룡이 이번 생에는 바라밀을 완성할 수 있을지.","JPN":"煉獄に落ちた龍が、今生では波羅蜜を完成できるか。","ENG":"Whether or not the dragon of Kleshas that has fallen into the purgatory can complete the Paramita in his current life.","TWN":"墜入煉獄的煩惱龍，這次能不能完成波羅蜜。"},"stage":{"bg":"SNOWYARD_01","slots":{"L":null,"C":{"char_id":"NAYUBIN_SIX_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};